parameters.jsCode:
let responseText = "### 🚨 Contract Risk Assessment Summary\n\nI have successfully analyzed the contract and identified **" + $input.all().length + "** critical risk elements:\n\n";

for (let i = 0; i < $input.all().length; i++) {
// Pull fields directly from the Supabase row output structure
let risk = $input.all()[i].json;

responseText += `🔹 **Risk #${i + 1} [${risk.risk_rating || 'Unknown'}]**\n`;
responseText += `* **Clause:** "${risk.clause_text || 'No text found'}"\n`;
responseText += `* **Analysis:** ${risk.risk_description || 'No analysis found'}\n\n`;
}

responseText += "---\n*All identified risks have been securely logged into the database.*";

return [{ json: { formatted_chat_response: responseText } }];

